// This used to silently skip, which can look like "it worked" while sending nothing.
// For OTP and password-reset flows we *must* fail loudly.
const err = new Error("Email service is not configured");
err.status = 500;
throw err;

// Use Resend's dev sender by default to avoid domain-verification issues.
const sendResult = await sendEmail({
  to: toEmail,
  subject,
  text,
  html,
  from: "WHCC <onboarding@resend.dev>",
});

// Resend typically returns { id: "..." }
const messageId = sendResult?.id || null;

return Response.json({ ok: true, messageId });

